<?php
$cmsAdminTitle='Lesson Content Controls';require_once __DIR__.'/../includes/cms-admin-header.php';$pathway=(string)($_GET['pathway']??'Kids');if(!in_array($pathway,['Kids','Business','General'],true))$pathway='Kids';$lessonId=(int)($_GET['lesson']??0);
if($pathway==='Kids')$lessons=$pdo->query('SELECT id,title FROM kids_lessons ORDER BY course_id,sort_order')->fetchAll();elseif($pathway==='Business')$lessons=$pdo->query('SELECT id,title FROM business_lessons ORDER BY course_id,sort_order')->fetchAll();else $lessons=$pdo->query('SELECT id,title FROM lms_lessons ORDER BY module_id,sort_order')->fetchAll();if(!$lessonId&&$lessons)$lessonId=(int)$lessons[0]['id'];
if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){$action=(string)$_POST['action'];$lessonId=(int)$_POST['lesson_id'];if($action==='settings'){$pdo->prepare('INSERT INTO lesson_content_settings (pathway,lesson_id,avatar_id,narration_media_id,quiz_button_text,activity_button_text,is_active) VALUES (?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE avatar_id=VALUES(avatar_id),narration_media_id=VALUES(narration_media_id),quiz_button_text=VALUES(quiz_button_text),activity_button_text=VALUES(activity_button_text),is_active=VALUES(is_active)')->execute([$pathway,$lessonId,(int)$_POST['avatar_id']?:null,(int)$_POST['narration_media_id']?:null,trim((string)$_POST['quiz_button_text']),trim((string)$_POST['activity_button_text']),isset($_POST['is_active'])?1:0]);}elseif($action==='block'){$id=(int)($_POST['id']??0);$data=[$pathway,$lessonId,$_POST['block_type'],trim((string)$_POST['title']),trim((string)$_POST['body_text']),(int)$_POST['media_id']?:null,trim((string)$_POST['button_text']),trim((string)$_POST['button_link']),trim((string)$_POST['settings_json']),max(1,(int)$_POST['sort_order']),isset($_POST['block_active'])?1:0];if($id){$data[]=$id;$pdo->prepare('UPDATE lesson_blocks SET pathway=?,lesson_id=?,block_type=?,title=?,body_text=?,media_id=?,button_text=?,button_link=?,settings_json=?,sort_order=?,is_active=? WHERE id=?')->execute($data);}else{$pdo->prepare('INSERT INTO lesson_blocks (pathway,lesson_id,block_type,title,body_text,media_id,button_text,button_link,settings_json,sort_order,is_active) VALUES (?,?,?,?,?,?,?,?,?,?,?)')->execute($data);}}elseif($action==='delete'){cms_require_delete_role();$pdo->prepare('DELETE FROM lesson_blocks WHERE id=?')->execute([(int)$_POST['id']]);}elseif($action==='toggle'){$pdo->prepare('UPDATE lesson_blocks SET is_active=1-is_active WHERE id=?')->execute([(int)$_POST['id']]);}header('Location: academy-lesson-content.php?pathway='.$pathway.'&lesson='.$lessonId);exit;}
$s=$pdo->prepare('SELECT * FROM lesson_content_settings WHERE pathway=? AND lesson_id=?');$s->execute([$pathway,$lessonId]);$settings=$s->fetch()?:['avatar_id'=>0,'narration_media_id'=>0,'quiz_button_text'=>'Take Quiz','activity_button_text'=>'Start Activity','is_active'=>1];$edit=null;if(!empty($_GET['edit_block'])){$s=$pdo->prepare('SELECT * FROM lesson_blocks WHERE id=?');$s->execute([(int)$_GET['edit_block']]);$edit=$s->fetch();}$s=$pdo->prepare('SELECT b.*,m.title media_title FROM lesson_blocks b LEFT JOIN media_library m ON m.id=b.media_id WHERE b.pathway=? AND b.lesson_id=? ORDER BY b.sort_order,b.id');$s->execute([$pathway,$lessonId]);$blocks=$s->fetchAll();$avatars=cms_avatar_options($pdo);$media=cms_media_options($pdo);
?>
<div class="admin-top"><div><p class="eyebrow">Every lesson element</p><h1>Lesson Content Controls</h1></div></div><div class="d-flex gap-2 mb-3"><?php foreach(['Kids','Business','General'] as $v):?><a class="btn <?=$pathway===$v?'btn-premium':'btn-outline-light'?>" href="?pathway=<?=$v?>"><?=$v?></a><?php endforeach?></div><form class="glass-card mb-4"><input type="hidden" name="pathway" value="<?=e($pathway)?>"><label>Lesson<select class="form-select mt-2" name="lesson" onchange="this.form.submit()"><?php foreach($lessons as $l):?><option value="<?=(int)$l['id']?>" <?=$lessonId===(int)$l['id']?'selected':''?>><?=e($l['title'])?></option><?php endforeach?></select></label></form>
<form class="glass-card cms-form mb-4" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="settings"><input type="hidden" name="lesson_id" value="<?=$lessonId?>"><label>Teacher / coach avatar<select class="form-select" name="avatar_id"><option value="0">Default avatar</option><?php foreach($avatars as $a):?><option value="<?=(int)$a['id']?>" <?=(int)$settings['avatar_id']===(int)$a['id']?'selected':''?>><?=e($a['name'].' · '.$a['learner_type'])?></option><?php endforeach?></select></label><label>Voice narration media<select class="form-select" name="narration_media_id"><option value="0">No audio narration</option><?php foreach($media as $m):if($m['file_type']==='audio'):?><option value="<?=(int)$m['id']?>" <?=(int)$settings['narration_media_id']===(int)$m['id']?'selected':''?>><?=e($m['title'])?></option><?php endif;endforeach?></select></label><label>Quiz button text<input class="form-control" name="quiz_button_text" value="<?=e($settings['quiz_button_text'])?>"></label><label>Activity button text<input class="form-control" name="activity_button_text" value="<?=e($settings['activity_button_text'])?>"></label><label><input type="checkbox" name="is_active" value="1" <?=$settings['is_active']?'checked':''?>> Lesson visible</label><div><button class="btn btn-premium">Save lesson controls</button></div></form>
<form class="glass-card cms-form mb-4" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="block"><input type="hidden" name="lesson_id" value="<?=$lessonId?>"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><label>Block type<select class="form-select" name="block_type"><?php foreach(['story','text','step','media','video','lottie','audio','download','checklist','quiz_link','activity_link'] as $v):?><option <?=($edit['block_type']??'text')===$v?'selected':''?>><?=$v?></option><?php endforeach?></select></label><label>Title<input class="form-control" name="title" value="<?=e($edit['title']??'')?>"></label><label class="wide">Content<textarea class="form-control" name="body_text"><?=e($edit['body_text']??'')?></textarea></label><label>Media<select class="form-select" name="media_id"><option value="0">No media</option><?php foreach($media as $m):?><option value="<?=(int)$m['id']?>" <?=(int)($edit['media_id']??0)===(int)$m['id']?'selected':''?>><?=e($m['title'])?></option><?php endforeach?></select></label><label>Order<input class="form-control" type="number" name="sort_order" value="<?=(int)($edit['sort_order']??1)?>"></label><label>Button text<input class="form-control" name="button_text" value="<?=e($edit['button_text']??'')?>"></label><label>Button link<input class="form-control" name="button_link" value="<?=e($edit['button_link']??'')?>"></label><label class="wide">Settings JSON<textarea class="form-control" name="settings_json"><?=e($edit['settings_json']??'')?></textarea></label><label><input type="checkbox" name="block_active" value="1" <?=($edit['is_active']??1)?'checked':''?>> Block visible</label><div><button class="btn btn-premium">Save lesson block</button></div></form>
<div class="glass-card table-responsive"><table class="table table-dark"><tr><th>Order</th><th>Block</th><th>Type</th><th>Media</th><th>Visible</th><th></th></tr><?php foreach($blocks as $b):?><tr><td><?=(int)$b['sort_order']?></td><td><strong><?=e($b['title'])?></strong><small class="d-block text-secondary"><?=e(mb_strimwidth((string)$b['body_text'],0,80,'…'))?></small></td><td><?=e($b['block_type'])?></td><td><?=e($b['media_title']??'—')?></td><td><?=$b['is_active']?'Yes':'No'?></td><td><a href="?pathway=<?=$pathway?>&lesson=<?=$lessonId?>&edit_block=<?=(int)$b['id']?>">Edit</a><form class="d-inline" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="lesson_id" value="<?=$lessonId?>"><input type="hidden" name="id" value="<?=(int)$b['id']?>"><button class="btn btn-sm btn-outline-warning" name="action" value="toggle">Toggle</button><?php if(cms_can_delete()):?><button class="btn btn-sm btn-danger" name="action" value="delete">Delete</button><?php endif?></form></td></tr><?php endforeach?></table></div>
<?php require_once __DIR__.'/../includes/cms-admin-footer.php';?>